var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"민하 씨, 여고생인데 운전면허가 있었군요.","JPN":"ミウさん、女子高生なのに免許持ってるんですね。","ENG":"Minha, you're a high schooler, but you already have a driver's license.","TWN":"敏荷你是女高中生，卻有駕照呢。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"예전에 땄어. 혼자 돌아다닐 일이 많았거든.","JPN":"昔取ったんだ。一人で移動することが多かったし。","ENG":"I got it a while ago. I travel around on my own a lot.","TWN":"我以前考的。我常常一個人到處跑。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…민하 씨는 절 어떻게 찾았어요?","JPN":"……ミウさんは、どうやって私を見つけたんですか？","ENG":"...How did you find me?","TWN":"……你是怎麼找到我的？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"시니어가 의심 가는 장소 몇 군데를 짚어줬어. 그라운드 원에 사각지대가 그리 많진 않으니까.","JPN":"シニアが疑わしい場所をいくつかピックアップしてくれてね。そもそもグラウンド・ワンに死角はそんなに多くないから。","ENG":"The Senior pointed out a few suspicious locations. There aren't that many blind spots in Ground One.","TWN":"Senior點出了幾個可疑地點。G1的死角不多。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"설마, 녀석들이 그런 엉뚱한 장소에 나타날 줄은 몰랐지만.","JPN":"まさかやつらがあんな突拍子もない場所に現れるとは思わなかったけど。","ENG":"Didn't expect them to show up somewhere that random, though.","TWN":"只是我沒想到他們會出現在那種地方。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"보안을 뚫고 대균열 안으로 들어가려 했어요. 거기서 뭘 얻으려던 걸까요?","JPN":"セキュリティを突破して大亀裂の中に入ろうとしていました。そこで何をするつもりだったんでしょうか。","ENG":"They tried to break through security and enter the Grand Dimension Crevice. What were they after?","TWN":"他們突破保安、進入大峽谷，是為了拿到什麼？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"Who knows.","TWN":"這個我也不清楚。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"방금 전까지 침식사태를 수습하는 동안 실종자 신고가 제법 들어왔어.","JPN":"さっきまで侵食事態を収拾してたんだけど、失踪者の報告が結構入ってきてた。","ENG":"While we were dealing with the Corruption disaster earlier, we got quite a few missing person reports.","TWN":"剛才處理侵蝕事件時，也收到不少失蹤通報。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"당연히 그 침입자 놈들의 짓이라 생각했는데… 착각이 아니라면 놈들의 계략은 한 두 가지가 아닌 것 같아.","JPN":"当然侵入者どもの仕業だと思ってたけど……こうなると、騒ぎ1つや2つどころじゃ済まないかもしれないわね。","ENG":"Naturally, I assumed it was the intruders' doing... But if I'm not mistaken, they're running more than one scheme at once.","TWN":"我本來以為都是那些入侵者搞的鬼……但如果我沒猜錯，他們的計畫不只一個。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"벨제부브라고 했었죠? 침입자들은 그 마왕이란 존재를 따르는 거고요.","JPN":"ベルゼブブでしたっけ？　侵入者たちはその魔王に従っているんですね。","ENG":"You said Beelzebub, right? The intruders serve that Demon Lord.","TWN":"你剛說別西卜對吧？入侵者就是追隨那個魔王吧？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"마왕이란 건… 민하 씨에게 있어서 상대할 만한 존재인가요?","JPN":"魔王というのは……ミウさんにとって、相手ができそうな存在なんですか？","ENG":"A Demon Lord is... something you can actually face, Minha?","TWN":"魔王……對敏荷來說，是能對付的對象嗎？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아마 어렵지 않을까?","JPN":"難しいんじゃないかな。","ENG":"Probably not easily.","TWN":"應該不難吧？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그래도 벨제부브가 내 앞에 직접 나타난다면, 도망칠 수 있어도 싸우긴 할 거야.","JPN":"でもベルゼブブが私の前に現れたら、とりあえず戦うつもり。逃げるチャンスがあってもね。","ENG":"Still, if Beelzebub showed up in front of me, I'd fight. Even if running away were an option.","TWN":"但如果別西卜親自出現在我面前，就算逃得了，我也會選擇戰鬥。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그건, 공인 카운터로서의 사명 같은 건가요?","JPN":"公認カウンターとしての使命感ですか？","ENG":"Is that a sense of duty, as an Official Counter?","TWN":"那是作為認證制裁者的使命嗎？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"풋, 그런 사명이 있었으면 시니어 말대로 얌전히 그라운드 원이나 지켰겠지.","JPN":"ぷっ、使命感なんてもんがあったら、シニアの言う通り大人しくグラウンド・ワンを守ってたよ。","ENG":"Pfft. If I had that kind of sense of duty, I'd have stayed put guarding Ground One like the Senior wanted.","TWN":"噗。如果真有那種使命感，我早就乖乖守在G1了。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"원래 그라운드 원의 공인 카운터는 내가 아니었어.","JPN":"もともとグラウンド・ワンの公認カウンターは私じゃなかった。","ENG":"I wasn't originally Ground One's Official Counter.","TWN":"原本G1的認證制裁者不是我。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"잠깐 공석이 된 그 자릴 어쩌다 보니 내가 떠맡았을 뿐이야.","JPN":"少しの間空席になっていたその役目を、なりゆきで任されてしまっただけ。","ENG":"The position opened up for a bit, and I just ended up taking it.","TWN":"只是那個位置一度空缺，剛好被我接下來而已。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"공인 카운터의 자리가 공석이 됐다는 건… 어떤 의미죠?","JPN":"公認カウンターが空席って……どういうことですか？","ENG":"If the Official Counter position became vacant... what does that mean?","TWN":"認證制裁者的位置空缺……那代表什麼意思？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"살해당했어.","JPN":"殺されたんだ。","ENG":"The former one was murdered.","TWN":"被殺了。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕 벨제부브의 낙인이 찍힌 채로.","JPN":"魔王ベルゼブブの烙印が押されて。","ENG":"Branded with the mark of the Demon Lord Beelzebub.","TWN":"在被烙上魔王別西卜的烙印後。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…살해…","JPN":"……殺された……","ENG":"...Murdered...","TWN":"……被殺……"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"2년 전, 그 배후를 파헤치던 사람들이 전부 죽었어.","JPN":"2年前、背後を探っていた人は全員死んだ。","ENG":"Two years ago, everyone who tried to dig into what was behind them died.","TWN":"2年前，追查他們底細的人全都死了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 중엔 <color=#ffd34c>S급 카운터</color>도 있었고.","JPN":"その中には<color=#ffd34c>S級カウンター</color>だっていた。","ENG":"That included a <color=#ffd34c>Grade S Counter</color>.","TWN":"其中還有<color=#ffd34c>S級制裁者</color>。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"지금 민하 씨가 하고 있는 건…누군가의 복수인가요?","JPN":"今ミウさんがやろうとしているのは……誰かの復讐ですか？","ENG":"What you're doing now... is it revenge for someone?","TWN":"現在敏荷正在做的事……是某個人的復仇嗎？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 사람은 나한테 인생을 가르쳐준 스승이었어. 유일한 가족이기도 했고.","JPN":"その人は私に人生を教えてくれた師匠で、唯一の家族だった。","ENG":"That person was my master. The one who taught me how to live. My only family.","TWN":"那個人，是我的人生導師，也是我唯一的家人。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니는 이해 못할 거야. 이미 죽은 사람 때문에, 이렇게까지 한다는 거.","JPN":"姉さんにはわからないかもね。死んだ人のためにここまでやるってのが。","ENG":"You wouldn't understand. Going this far over someone who's already dead.","TWN":"姐姐你不會懂的。因為一個已經死去的人，做到這種地步。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아니에요. 실은 저도…","JPN":"そんなことありません。実は私も……","ENG":"No. Actually, I–","TWN":"不，其實我也……"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};